package com.gabriel.benchmark;

/**
 * Represents the result of a benchmark execution.
 *
 * @param algorithm name of the benchmarked algorithm
 * @param executionTimeNs execution time in nanoseconds
 */
public record BenchmarkResult(
        String algorithm,
        long executionTimeNs
) {

    /**
     * Returns the execution time in milliseconds.
     *
     * @return execution time in milliseconds
     */
    public double executionTimeMs() {
        return executionTimeNs / 1_000_000.0;
    }

    /**
     * Returns a formatted representation of the benchmark result.
     *
     * @return formatted benchmark result
     */
    @Override
    public String toString() {
        return """
                Algorithm: %s
                Execution Time: %.3f ms
                """.formatted(algorithm, executionTimeMs());
    }
}